#include <stdio.h>
struct Node {
    struct Node* next;
    unsigned int x;
};
int main() {
    struct Node t1={0,5u}, t2={0,7u}, t3={0,11u};
    t3.next=&t2; t2.next=&t1;
    struct Node* curr=&t3;
    int sum=0;
    while(curr) {
        sum = sum*3 + curr->x;
        curr = curr->next;
    }
    sum = (sum^42u) + 100u;
    printf("%u\n", sum);
}

